                    className="w-full" 
                    variant="outline"
                    onClick={() => exportOrdersToExcel(orders)}
                  >
                    <Download className="w-4 h-4 mr-2" />
                    Excel Yuklab Olish
                  </Button>
                </CardContent>
              </Card>
            </div>
          </TabsContent>

          <TabsContent value="orders" className="space-y-6">
            <Card data-testid="card-orders-admin">
              <CardHeader>
                <CardTitle className="flex items-center justify-between">
                  Barcha Buyurtmalar
                  <Badge variant="outline">{orders.length}</Badge>
                </CardTitle>
              </CardHeader>
              <CardContent>
                {ordersLoading ? (
                  <div className="space-y-4">
                    {[...Array(5)].map((_, i) => (
                      <div key={i} className="animate-pulse">
                        <div className="h-6 bg-neutral-200 rounded w-3/4 mb-2"></div>
                        <div className="h-4 bg-neutral-200 rounded w-1/2"></div>
                      </div>
                    ))}
                  </div>
                ) : orders.length === 0 ? (
                  <p className="text-neutral-500 text-center py-8">Buyurtmalar mavjud emas</p>
                ) : (
                  <div className="overflow-x-auto">
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead>Hamkor</TableHead>
                          <TableHead>Mijoz</TableHead>
                          <TableHead>Mahsulot</TableHead>
                          <TableHead>Miqdor</TableHead>
                          <TableHead>Summa</TableHead>
                          <TableHead>Status</TableHead>
                          <TableHead>Sana</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {orders.map((order: OrderWithDetails) => (
                          <TableRow key={order.id}>
                            <TableCell>
                              <div className="flex items-center space-x-2">
                                <Avatar className="h-6 w-6">
                                  <AvatarImage src={order.partner.user.profileImageUrl || ""} />
                                  <AvatarFallback className="text-xs">
                                    {(order.partner.user.firstName?.[0] || order.partner.user.email[0]).toUpperCase()}
                                  </AvatarFallback>
                                </Avatar>
                                <span className="text-sm" data-testid={`text-order-partner-${order.id}`}>
                                  {order.partner.user.firstName || order.partner.user.email}
                                </span>
                              </div>
                            </TableCell>
                            <TableCell data-testid={`text-order-customer-${order.id}`}>
                              {order.customerName}
                            </TableCell>
                            <TableCell data-testid={`text-order-product-${order.id}`}>
                              {order.product.name}
                            </TableCell>
                            <TableCell data-testid={`text-order-quantity-${order.id}`}>
                              {order.quantity}
                            </TableCell>
                            <TableCell data-testid={`text-order-amount-${order.id}`}>
                              {Number(order.totalAmount).toLocaleString()} so'm
                            </TableCell>
                            <TableCell>
                              {getStatusBadge(order.status)}
                            </TableCell>
                            <TableCell data-testid={`text-order-date-${order.id}`}>
                              {new Date(order.createdAt).toLocaleDateString('uz-UZ')}
                            </TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="chat">
            <Card>
              <CardHeader>
                <CardTitle>Chat Tizimi</CardTitle>
                <CardDescription>Admin va hamkorlar uchun aloqa tizimi</CardDescription>
              </CardHeader>
              <CardContent>
                <div className="text-center py-8 text-neutral-500">
                  Chat tizimi tez orada ishga tushiriladi
                </div>
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      </div>

      {/* Mini Warehouse Modal */}
      <Dialog open={warehouseModalOpen} onOpenChange={setWarehouseModalOpen}>
        <DialogContent className="max-w-4xl max-h-[80vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle className="flex items-center space-x-2">
              <Warehouse className="h-5 w-5" />
              <span>{selectedPartner?.businessName} - Mini Sklad</span>
            </DialogTitle>
          </DialogHeader>

          {warehouseLoading ? (
            <div className="flex items-center justify-center py-12">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
              <span className="ml-2">Sklad ma'lumotlari yuklanmoqda...</span>
            </div>
          ) : warehouseData ? (
            <div className="space-y-6">
              {/* Summary Cards */}
              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <Card className="border-l-4 border-l-blue-500">
                  <CardContent className="p-4">
                    <p className="text-sm text-neutral-600">Jami Mahsulotlar</p>
                    <p className="text-2xl font-bold text-blue-600">
                      {warehouseData.summary.totalProducts}
                    </p>
                  </CardContent>
                </Card>
                <Card className="border-l-4 border-l-green-500">
                  <CardContent className="p-4">
                    <p className="text-sm text-neutral-600">Jami Qoldiq</p>
                    <p className="text-2xl font-bold text-green-600">
                      {warehouseData.summary.totalStock}
                    </p>
                  </CardContent>
                </Card>
                <Card className="border-l-4 border-l-purple-500">
                  <CardContent className="p-4">
                    <p className="text-sm text-neutral-600">Jami Qiymat</p>
                    <p className="text-2xl font-bold text-purple-600">
                      {warehouseData.summary.totalValue.toLocaleString()} so'm
                    </p>
                  </CardContent>
                </Card>
                <Card className="border-l-4 border-l-orange-500">
                  <CardContent className="p-4">
                    <p className="text-sm text-neutral-600">Jami Daromad</p>
                    <p className="text-2xl font-bold text-orange-600">
                      {warehouseData.summary.totalRevenue.toLocaleString()} so'm
                    </p>
                  </CardContent>
                </Card>
              </div>

              {/* Products Table */}
              <Card>
                <CardHeader>
                  <CardTitle>Mahsulotlar Ro'yxati</CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="overflow-x-auto">
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead>Nomi</TableHead>
                          <TableHead>Rasm</TableHead>
                          <TableHead>Qoldiq</TableHead>
                          <TableHead>Sebestoimost</TableHead>
                          <TableHead>Jami Qiymat</TableHead>
                          <TableHead>Daromad</TableHead>
                          <TableHead>Foyda</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {warehouseData.products.map((product: any) => (
                          <TableRow key={product.id}>
                            <TableCell className="font-medium">
                              {product.name}
                            </TableCell>
                            <TableCell>
                              <div className="w-12 h-12 bg-neutral-100 rounded-lg flex items-center justify-center">
                                {product.imageUrl ? (
                                  <img 
                                    src={product.imageUrl} 
                                    alt={product.name}
                                    className="w-10 h-10 object-cover rounded"
                                  />
                                ) : (
                                  <Package className="w-6 h-6 text-neutral-400" />
                                )}
                              </div>
                            </TableCell>
                            <TableCell>
                              <Badge variant={product.currentStock <= 5 ? "destructive" : "secondary"}>
                                {product.currentStock}
                              </Badge>
                            </TableCell>
                            <TableCell>
                              {product.costPrice.toLocaleString()} so'm
                            </TableCell>
                            <TableCell>
                              {product.stockValue.toLocaleString()} so'm
                            </TableCell>
                            <TableCell className="text-green-600 font-medium">
                              {product.revenue.toLocaleString()} so'm
                            </TableCell>
                            <TableCell className="text-blue-600 font-medium">
                              {product.profit.toLocaleString()} so'm
                            </TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </div>
                </CardContent>
              </Card>
            </div>
          ) : (
            <div className="text-center py-8">
              <p className="text-neutral-500">Sklad ma'lumotlari topilmadi</p>
            </div>
          )}
        </DialogContent>
      </Dialog>


    </div>
  );
}

